list_skills() { echo -e "${CYAN}Skills:${NC}
"; jq -r '.skills | group_by(.status) | .[] | "  " + (if .[0].status == "discovered" then "🔍" elif .[0].status == "learned" then "📖" else "⭐" end) + " [" + .[0].status + "]
" + (map("    \(.name) — \(.desc)") | join("
"))' "$SKILLS" 2>/dev/null || echo "  (empty)"; }
